  ((SELECT id FROM mock_test_bank WHERE exam_type = 'TOPIK_II' AND test_number = 37 ORDER BY created_at DESC LIMIT 1), 'listening', 1, '여자:어?비밀번호맞게눌렀는데왜안열리지?남자:제가한번해볼게요.정말안되네요.여자:고장났나봐요.제가가서경비아저씨불러올게요.', NULL, 'https://ywtxdfwntobzegrlyplw.supabase.co/storage/v1/object/public/mock%20test%20files/topik-ii-37/audio/37th-TOPIK-II-Listening-Audio-File-64k-mono.mp3', '["https://ywtxdfwntobzegrlyplw.supabase.co/storage/v1/object/public/mock%20test%20files/topik-ii-37/listening/q1_option_1.png", "https://ywtxdfwntobzegrlyplw.supabase.co/storage/v1/object/public/mock%20test%20files/topik-ii-37/listening/q1_option_2.png", "https://ywtxdfwntobzegrlyplw.supabase.co/storage/v1/object/public/mock%20test%20files/topik-ii-37/listening/q1_option_3.png", "https://ywtxdfwntobzegrlyplw.supabase.co/storage/v1/object/public/mock%20test%20files/topik-ii-37/listening/q1_option_4.png"]'::jsonb, '["①", "②", "③", "④"]'::jsonb, 2, '③', NULL),
  ((SELECT id FROM mock_test_bank WHERE exam_type = 'TOPIK_II' AND test_number = 37 ORDER BY created_at DESC LIMIT 1), 'listening', 2, '남자:정말축하해요.준비하느라고생했죠?이거받으세요.여자:뭘이런거까지준비했어요.바쁘신데와줘서고마워요.남자:와,손님이많네요.가게도꽤크고요.', NULL, 'https://ywtxdfwntobzegrlyplw.supabase.co/storage/v1/object/public/mock%20test%20files/topik-ii-37/audio/37th-TOPIK-II-Listening-Audio-File-64k-mono.mp3', '["https://ywtxdfwntobzegrlyplw.supabase.co/storage/v1/object/public/mock%20test%20files/topik-ii-37/listening/q2_option_1.png", "https://ywtxdfwntobzegrlyplw.supabase.co/storage/v1/object/public/mock%20test%20files/topik-ii-37/listening/q2_option_2.png", "https://ywtxdfwntobzegrlyplw.supabase.co/storage/v1/object/public/mock%20test%20files/topik-ii-37/listening/q2_option_3.png", "https://ywtxdfwntobzegrlyplw.supabase.co/storage/v1/object/public/mock%20test%20files/topik-ii-37/listening/q2_option_4.png"]'::jsonb, '["①", "②", "③", "④"]'::jsonb, 2, '①', NULL),
  ((SELECT id FROM mock_test_bank WHERE exam_type = 'TOPIK_II' AND test_number = 37 ORDER BY created_at DESC LIMIT 1), 'listening', 3, '남자:30대여성을대상으로화장품구매장소를조사한결과화장품전문매장을가장많이이용하는것으로나타났습니다.그다음으로는백화점과대형마트가뒤를이었는데백화점이용객은지난해에비해서크게줄어든것으로조사되었습니다.', NULL, 'https://ywtxdfwntobzegrlyplw.supabase.co/storage/v1/object/public/mock%20test%20files/topik-ii-37/audio/37th-TOPIK-II-Listening-Audio-File-64k-mono.mp3', '["https://ywtxdfwntobzegrlyplw.supabase.co/storage/v1/object/public/mock%20test%20files/topik-ii-37/listening/q3_option_1.png", "https://ywtxdfwntobzegrlyplw.supabase.co/storage/v1/object/public/mock%20test%20files/topik-ii-37/listening/q3_option_2.png", "https://ywtxdfwntobzegrlyplw.supabase.co/storage/v1/object/public/mock%20test%20files/topik-ii-37/listening/q3_option_3.png", "https://ywtxdfwntobzegrlyplw.supabase.co/storage/v1/object/public/mock%20test%20files/topik-ii-37/listening/q3_option_4.png"]'::jsonb, '["①", "②", "③", "④"]'::jsonb, 2, '②', NULL),
  ((SELECT id FROM mock_test_bank WHERE exam_type = 'TOPIK_II' AND test_number = 37 ORDER BY created_at DESC LIMIT 1), 'listening', 4, '남자:소설가박인수씨가오늘강연하러학교에온대.여자:그래?몇시시작인데?난3시까지수업이있어서.남자:__________________________________________________', NULL, 'https://ywtxdfwntobzegrlyplw.supabase.co/storage/v1/object/public/mock%20test%20files/topik-ii-37/audio/37th-TOPIK-II-Listening-Audio-File-64k-mono.mp3', NULL, '["제시간에도착해서다행이야.", "수업끝나고가도늦지않아.", "강연은누구든지들을수있어.", "시간이얼마나걸릴지모르겠어."]'::jsonb, 2, '제시간에도착해서다행이야.', NULL),
  ((SELECT id FROM mock_test_bank WHERE exam_type = 'TOPIK_II' AND test_number = 37 ORDER BY created_at DESC LIMIT 1), 'listening', 5, '남자:수진씨,다음주부터봉사활동간다면서요?여자:네.꼭해보고싶었던일이라휴가를냈어요.남자:__________________________________________________', NULL, 'https://ywtxdfwntobzegrlyplw.supabase.co/storage/v1/object/public/mock%20test%20files/topik-ii-37/audio/37th-TOPIK-II-Listening-Audio-File-64k-mono.mp3', NULL, '["정말좋은기회니까잘쉬고와요.", "그렇게하고싶어하는줄몰랐어요.", "특별히휴가를낼만큼바빴나봐요.", "그래도가기로한건데잘해보세요."]'::jsonb, 2, '그렇게하고싶어하는줄몰랐어요.', NULL),
  ((SELECT id FROM mock_test_bank WHERE exam_type = 'TOPIK_II' AND test_number = 37 ORDER BY created_at DESC LIMIT 1), 'listening', 6, '여자:이거교환기간이지났는데바꿀수있을까?남자:한번도안입었으니까한번물어봐.여자:__________________________________________________', NULL, 'https://ywtxdfwntobzegrlyplw.supabase.co/storage/v1/object/public/mock%20test%20files/topik-ii-37/audio/37th-TOPIK-II-Listening-Audio-File-64k-mono.mp3', NULL, '["바꿔주면좋겠는데.", "물어볼필요는없겠지.", "날짜가지났을지몰라.", "빨리입어볼걸그랬어."]'::jsonb, 2, '물어볼필요는없겠지.', NULL),
  ((SELECT id FROM mock_test_bank WHERE exam_type = 'TOPIK_II' AND test_number = 37 ORDER BY created_at DESC LIMIT 1), 'listening', 7, '남자:수민씨,요즘도아침식사를배달해먹어요?여자:네,한달쯤됐는데요.아침에여유가있어서좋은것같아요.남자:__________________________________________________', NULL, 'https://ywtxdfwntobzegrlyplw.supabase.co/storage/v1/object/public/mock%20test%20files/topik-ii-37/audio/37th-TOPIK-II-Listening-Audio-File-64k-mono.mp3', NULL, '["저도가게에가서사야겠어요.", "그집연락처좀알려주세요.", "아침을준비하려면바쁘겠어요.", "일할때먹을수있어서좋아요."]'::jsonb, 2, '아침을준비하려면바쁘겠어요.', NULL),
  ((SELECT id FROM mock_test_bank WHERE exam_type = 'TOPIK_II' AND test_number = 37 ORDER BY created_at DESC LIMIT 1), 'listening', 8, '여자:다음달에열리는전시회기획안입니다.검토좀부탁드리겠습니다.남자:수고했어요,지영씨.그런데전시회초대손님명단은다정리되어가나요?여자:__________________________________________________', NULL, 'https://ywtxdfwntobzegrlyplw.supabase.co/storage/v1/object/public/mock%20test%20files/topik-ii-37/audio/37th-TOPIK-II-Listening-Audio-File-64k-mono.mp3', NULL, '["며칠더걸릴것같습니다.", "이미전시회를시작했습니다.", "다음달에초대하려고합니다.", "계획보다늦게올것같습니다."]'::jsonb, 2, '계획보다늦게올것같습니다.', NULL),
  ((SELECT id FROM mock_test_bank WHERE exam_type = 'TOPIK_II' AND test_number = 37 ORDER BY created_at DESC LIMIT 1), 'listening', 9, '여자:너영어잘하지?번역과제가있는데제대로했는지확인해줄수있어?남자:음,일단메일로보내봐.그런데언제까지해야되는데?여자:과제제출이다음주월요일이니까토요일까지보내줘.남자:알았어.그럼메일확인하고전화할게.', NULL, 'https://ywtxdfwntobzegrlyplw.supabase.co/storage/v1/object/public/mock%20test%20files/topik-ii-37/audio/37th-TOPIK-II-Listening-Audio-File-64k-mono.mp3', NULL, '["남자에게번역한과제를받는다.", "남자에게전화로번역을부탁한다.", "남자에게이메일로과제를보낸다.", "남자에게전화해서제출날짜를묻는다."]'::jsonb, 2, '남자에게이메일로과제를보낸다.', NULL),
  ((SELECT id FROM mock_test_bank WHERE exam_type = 'TOPIK_II' AND test_number = 37 ORDER BY created_at DESC LIMIT 1), 'listening', 10, '여자:관리사무소지요?아파트관리비고지서를아직못받아서요.남자:아,그렇습니까?혹시우편함은확인하셨나요?어제넣어드렸는데요.여자:봤는데없더라고요.지금관리사무소에가면받을수있나요?남자:네,오시면바로재발급해드리겠습니다.', NULL, 'https://ywtxdfwntobzegrlyplw.supabase.co/storage/v1/object/public/mock%20test%20files/topik-ii-37/audio/37th-TOPIK-II-Listening-Audio-File-64k-mono.mp3', NULL, '["사무실에전화해서고지서를받는다.", "고지서가있는지우편함을확인한다.", "고지서를받으러관리사무소에간다.", "우편함에관리비고지서를넣어둔다."]'::jsonb, 2, '고지서를받으러관리사무소에간다.', NULL),
  ((SELECT id FROM mock_test_bank WHERE exam_type = 'TOPIK_II' AND test_number = 37 ORDER BY created_at DESC LIMIT 1), 'listening', 11, '여자:민수씨,차가좀흔들리는것같아요.남자:그래요?너무빨라서그런거아닐까요?속도를좀줄여봐요.여자:마찬가지예요.카센터에서점검한지얼마안됐는데…….아무래도세워야겠어요.남자:조금더가면휴게소가나올거예요.혹시바퀴에문제가있는지내려서제가확인해볼게요.', NULL, 'https://ywtxdfwntobzegrlyplw.supabase.co/storage/v1/object/public/mock%20test%20files/topik-ii-37/audio/37th-TOPIK-II-Listening-Audio-File-64k-mono.mp3', NULL, '["차의속도가빠른지확인한다.", "차에서내려바퀴상태를본다.", "카센터에들러서차를점검한다.", "휴게소로들어가서차를세운다."]'::jsonb, 2, '휴게소로들어가서차를세운다.', NULL),
  ((SELECT id FROM mock_test_bank WHERE exam_type = 'TOPIK_II' AND test_number = 37 ORDER BY created_at DESC LIMIT 1), 'listening', 12, '남자:김실장님,신제품설명회준비는잘돼가요?여자:네,그런데설명회자료가아직도착안했어요.안내를도와줄사람도좀부족하고요.남자:그럼,자료제작회사에전화한번해보세요.저는도와줄아르바이트학생을구할수있는지알아볼게요.여자:네,그래요.그럼이따가다시봐요.', NULL, 'https://ywtxdfwntobzegrlyplw.supabase.co/storage/v1/object/public/mock%20test%20files/topik-ii-37/audio/37th-TOPIK-II-Listening-Audio-File-64k-mono.mp3', NULL, '["안내를도와줄학생을알아본다.", "필요한인원을정확하게조사한다.", "설명회자료제작회사에전화한다.", "직원을만나러설명회장소에간다."]'::jsonb, 2, '설명회자료제작회사에전화한다.', NULL),
  ((SELECT id FROM mock_test_bank WHERE exam_type = 'TOPIK_II' AND test_number = 37 ORDER BY created_at DESC LIMIT 1), 'listening', 13, '여자:민수야,미안한데도서관에서책좀빌려줄래?어제학생증을잃어버렸어.남자:도서관에가면도서관출입증을만들어주던데.여자:도서관출입증?사진이없는데…….사진이없어도만들어줘?남자:도서관에서사진을찍어줄거야.그사진으로만들면돼.', NULL, 'https://ywtxdfwntobzegrlyplw.supabase.co/storage/v1/object/public/mock%20test%20files/topik-ii-37/audio/37th-TOPIK-II-Listening-Audio-File-64k-mono.mp3', NULL, '["여자는사진을한장가지고있다.", "남자는여자에게학생증을빌려줬다.", "도서관에가면학생증을바로만들어준다.", "도서관출입증을만들려면사진이필요하다."]'::jsonb, 2, '도서관출입증을만들려면사진이필요하다.', NULL),
  ((SELECT id FROM mock_test_bank WHERE exam_type = 'TOPIK_II' AND test_number = 37 ORDER BY created_at DESC LIMIT 1), 'listening', 14, '여자:총무과에서안내말씀드리겠습니다.오늘오후두시부터소방시설점검을실시할예정입니다.점검중에비상경보벨이작동될수있습니다.그리고엘리베이터를사용할수없으니계단을이용해주시기바랍니다.조금불편하시더라도양해해주시면감사하겠습니다.', NULL, 'https://ywtxdfwntobzegrlyplw.supabase.co/storage/v1/object/public/mock%20test%20files/topik-ii-37/audio/37th-TOPIK-II-Listening-Audio-File-64k-mono.mp3', NULL, '["점검을할때비상벨이울릴수있다.", "불편한점은총무과에전화하면된다.", "점검하는동안계단으로가면안된다.", "소방점검은두시간동안진행될것이다."]'::jsonb, 2, '점검을할때비상벨이울릴수있다.', NULL),
  ((SELECT id FROM mock_test_bank WHERE exam_type = 'TOPIK_II' AND test_number = 37 ORDER BY created_at DESC LIMIT 1), 'listening', 15, '남자:다음은알뜰경제소식입니다.자주고장나는복사기때문에불편한사무실이많죠?최근복사기를1년이상빌려주는서비스가화제입니다.복사기관리비는물론수리비도복사기회사에서부담하는데요.빌려쓰면복사기를사는것에비해서연100만원정도절약된다고합니다.이런장점때문에복사기를빌려쓰는사무실이늘어날것으로보입니다.', NULL, 'https://ywtxdfwntobzegrlyplw.supabase.co/storage/v1/object/public/mock%20test%20files/topik-ii-37/audio/37th-TOPIK-II-Listening-Audio-File-64k-mono.mp3', NULL, '["복사기대여기간은최대1년이다.", "복사기가고장나면수리를해준다.", "복사기대여는편리하지만비경제적이다.", "복사기를빌리면관리비는본인부담이다."]'::jsonb, 2, '복사기가고장나면수리를해준다.', NULL),
  ((SELECT id FROM mock_test_bank WHERE exam_type = 'TOPIK_II' AND test_number = 37 ORDER BY created_at DESC LIMIT 1), 'listening', 16, '여자:시장님,시청연수원을시민을위한문화공간으로바꾸는공사가진행중인것으로아는데요.소개좀부탁드립니다.남자:네,시청연수원은시설이낡아서몇년간비워두었던곳입니다.그래서재건축을계획하면서시민들의생각을알아봤더니문화공간으로사용하자는의견이많았습니다.앞으로이곳은공연장이나행사장으로활용할계획입니다.다음달이면우리시에도새로운문화공간이탄생하는것이죠.', NULL, 'https://ywtxdfwntobzegrlyplw.supabase.co/storage/v1/object/public/mock%20test%20files/topik-ii-37/audio/37th-TOPIK-II-Listening-Audio-File-64k-mono.mp3', NULL, '["이곳은오래된문화공간이다.", "이곳은시민들이직접사용하고있다.", "이곳은다음달에새로문을열계획이다.", "이곳은시장을위한공간으로바뀔것이다."]'::jsonb, 2, '이곳은다음달에새로문을열계획이다.', NULL),
  ((SELECT id FROM mock_test_bank WHERE exam_type = 'TOPIK_II' AND test_number = 37 ORDER BY created_at DESC LIMIT 1), 'listening', 17, '남자:수미씨,왜회사동호회에가입안해요?여자:저는따로활동하는동호회가있어요.그래서회사동호회는가입안하려고요.개인생활까지알게되면좀불편할것같아서요.남자:취미생활을같이하면회사사람들이랑빨리친해질수있어요.필요할때조언도구할수있고요.', NULL, 'https://ywtxdfwntobzegrlyplw.supabase.co/storage/v1/object/public/mock%20test%20files/topik-ii-37/audio/37th-TOPIK-II-Listening-Audio-File-64k-mono.mp3', NULL, '["회사동호회활동은부담스럽다.", "회사에동호회가많았으면좋겠다.", "회사동호회활동은직장생활에도움이된다.", "직장생활과동호회활동은따로해야한다."]'::jsonb, 2, '회사동호회활동은직장생활에도움이된다.', NULL),
  ((SELECT id FROM mock_test_bank WHERE exam_type = 'TOPIK_II' AND test_number = 37 ORDER BY created_at DESC LIMIT 1), 'listening', 18, '남자:이건지금까지발행된올림픽기념우표인가봐요.여자:네.정말멋있네요.올림픽의역사를보여주는것같아요.남자:사실기념우표를왜발행하는지잘이해가안됐어요.그런데전시회에와보니까의미를알겠어요.특히역사적인가치가큰것같아요.', NULL, 'https://ywtxdfwntobzegrlyplw.supabase.co/storage/v1/object/public/mock%20test%20files/topik-ii-37/audio/37th-TOPIK-II-Listening-Audio-File-64k-mono.mp3', NULL, '["기념우표는전시회에서발행된다.", "기념우표는역사적의미를담고있다.", "기념우표를전시하는것은역사적인일이다.", "기념우표를보여주는것은의미있는일이다."]'::jsonb, 2, '기념우표는역사적의미를담고있다.', NULL),
  ((SELECT id FROM mock_test_bank WHERE exam_type = 'TOPIK_II' AND test_number = 37 ORDER BY created_at DESC LIMIT 1), 'listening', 19, '남자:저드라마역사하고너무다른거아냐?작가가제대로알고썼는지모르겠네.여자:그냥드라마일뿐이잖아.재미있게만들려고내용을좀각색했겠지.남자:역사드라마는시청률보다역사적인사실전달에더신경써야할것같아.시청자들이기대하는것도그런거아닐까?여자:그말도맞는데,시청자가원하는건역사공부가아니라재미야.', NULL, 'https://ywtxdfwntobzegrlyplw.supabase.co/storage/v1/object/public/mock%20test%20files/topik-ii-37/audio/37th-TOPIK-II-Listening-Audio-File-64k-mono.mp3', NULL, '["역사드라마는시청률에의존한다.", "역사드라마는사실전달이중요하다.", "역사드라마는역사공부자료가된다.", "역사드라마는작가의의도대로제작된다."]'::jsonb, 2, '역사드라마는사실전달이중요하다.', NULL),
  ((SELECT id FROM mock_test_bank WHERE exam_type = 'TOPIK_II' AND test_number = 37 ORDER BY created_at DESC LIMIT 1), 'listening', 20, '여자:단장님께서는청소년을위한국악공연을하고계시는데요.특별히청소년을위한공연을하시는이유가있으신가요?남자:네.요즘청소년들은국악을지루하다고만생각하는것같습니다.그래서청소년들이국악을쉽게접하고즐기게하는것이필요한데요.대중가요를국악에맞게편곡해서연주하거나청소년들이직접전통악기를연주할수있는기회를주는것이죠.이렇게해서국악에대한편견을깨는것이중요한것같습니다.그래서앞으로도청소년을위한공연은계속할생각입니다.', NULL, 'https://ywtxdfwntobzegrlyplw.supabase.co/storage/v1/object/public/mock%20test%20files/topik-ii-37/audio/37th-TOPIK-II-Listening-Audio-File-64k-mono.mp3', NULL, '["청소년을대상으로국악교육을해야한다.", "청소년을위한국악공연이많아져야한다.", "청소년들에게전통악기를연주할기회를주어야한다.", "청소년들이갖고있는국악에대한태도를바꾸어야한다."]'::jsonb, 2, '청소년들이갖고있는국악에대한태도를바꾸어야한다.', NULL),
  ((SELECT id FROM mock_test_bank WHERE exam_type = 'TOPIK_II' AND test_number = 37 ORDER BY created_at DESC LIMIT 1), 'listening', 21, '여자:예전에가입해놓은쇼핑몰에서개인정보가유출됐다고연락이왔는데뭘어떻게해야되는거야?남자:개인정보유출?홈페이지에들어가서비밀번호부터바꿔야지.여자:자주이용하지도않는데가입하지말걸그랬어.그런데쇼핑몰에서개인정보를더철저하게관리해야하는거아냐?요즘사고가얼마나많은데…….남자:개인정보관리를쇼핑몰에다맡길수는없지.네가비밀번호라도자주바꿨으면이런일이없었을거야.
남자의중심생각으로맞는것을고르십시오.', NULL, 'https://ywtxdfwntobzegrlyplw.supabase.co/storage/v1/object/public/mock%20test%20files/topik-ii-37/audio/37th-TOPIK-II-Listening-Audio-File-64k-mono.mp3', NULL, '["쇼핑몰은개인정보를잘관리해야한다.", "쇼핑몰에가입하면쉽게개인정보가유출된다.", "개인정보유출을막으려면본인이신경써야한다.", "잘이용하지않는쇼핑몰에는가입하지말아야한다."]'::jsonb, 2, '개인정보유출을막으려면본인이신경써야한다.', NULL),
  ((SELECT id FROM mock_test_bank WHERE exam_type = 'TOPIK_II' AND test_number = 37 ORDER BY created_at DESC LIMIT 1), 'listening', 22, '여자:예전에가입해놓은쇼핑몰에서개인정보가유출됐다고연락이왔는데뭘어떻게해야되는거야?남자:개인정보유출?홈페이지에들어가서비밀번호부터바꿔야지.여자:자주이용하지도않는데가입하지말걸그랬어.그런데쇼핑몰에서개인정보를더철저하게관리해야하는거아냐?요즘사고가얼마나많은데…….남자:개인정보관리를쇼핑몰에다맡길수는없지.네가비밀번호라도자주바꿨으면이런일이없었을거야.
들은내용으로알맞은것을고르십시오.', NULL, 'https://ywtxdfwntobzegrlyplw.supabase.co/storage/v1/object/public/mock%20test%20files/topik-ii-37/audio/37th-TOPIK-II-Listening-Audio-File-64k-mono.mp3', NULL, '["여자는쇼핑몰가입을후회하고있다.", "여자는쇼핑몰의비밀번호를자주바꿨다.", "이쇼핑몰은개인정보유출사실을숨겼다.", "이쇼핑몰은개인정보없이가입할수있다."]'::jsonb, 2, '여자는쇼핑몰가입을후회하고있다.', NULL),
  ((SELECT id FROM mock_test_bank WHERE exam_type = 'TOPIK_II' AND test_number = 37 ORDER BY created_at DESC LIMIT 1), 'listening', 23, '남자:구청이죠?공원앞에있는야외무대를사용하고싶은데어떻게신청하나요?여자:어떤행사인가요?야외무대에서물건을팔거나상품을홍보하는경우에는사용할수없습니다.남자:네,알고있습니다.자선단체에서하는나눔행사입니다.무대행사는잠깐하고주로사람들에게홍보물을나눠줄건데요.여자:그래요?그런목적이라면신청가능해요.신청양식은구청홈페이지에서내려받으시면됩니다.행사후에는주변을깨끗이정리해주셔야합니다.
남자는무엇을하고있는지고르십시오.', NULL, 'https://ywtxdfwntobzegrlyplw.supabase.co/storage/v1/object/public/mock%20test%20files/topik-ii-37/audio/37th-TOPIK-II-Listening-Audio-File-64k-mono.mp3', NULL, '["야외무대위치에대해알아보고있다.", "야외무대사용에대해문의하고있다.", "야외무대에서행사진행을도와주고있다.", "야외무대에서상품홍보를준비하고있다."]'::jsonb, 2, '야외무대사용에대해문의하고있다.', NULL),
  ((SELECT id FROM mock_test_bank WHERE exam_type = 'TOPIK_II' AND test_number = 37 ORDER BY created_at DESC LIMIT 1), 'listening', 24, '남자:구청이죠?공원앞에있는야외무대를사용하고싶은데어떻게신청하나요?여자:어떤행사인가요?야외무대에서물건을팔거나상품을홍보하는경우에는사용할수없습니다.남자:네,알고있습니다.자선단체에서하는나눔행사입니다.무대행사는잠깐하고주로사람들에게홍보물을나눠줄건데요.여자:그래요?그런목적이라면신청가능해요.신청양식은구청홈페이지에서내려받으시면됩니다.행사후에는주변을깨끗이정리해주셔야합니다.
들은내용으로맞는것을고르십시오.', NULL, 'https://ywtxdfwntobzegrlyplw.supabase.co/storage/v1/object/public/mock%20test%20files/topik-ii-37/audio/37th-TOPIK-II-Listening-Audio-File-64k-mono.mp3', NULL, '["야외무대는구청에서관리한다.", "행사신청서는자선단체에제출한다.", "행사후주변청소는구청에서해준다.", "자선단체가물건을파는행사를하려고한다."]'::jsonb, 2, '야외무대는구청에서관리한다.', NULL),
  ((SELECT id FROM mock_test_bank WHERE exam_type = 'TOPIK_II' AND test_number = 37 ORDER BY created_at DESC LIMIT 1), 'listening', 25, '여자:선생님,이학교에는자기계발을스스로할수있는프로그램이있다고들었는데요.간단히소개해주시겠습니까?남자:네,자기계발프로그램은자기주도적으로이루어지는게중요한데우리학교의프로그램이그렇습니다.학생들은학기초에하고싶은일을정하고그중하나를골라계획서를제출합니다.학교에선중간에진도만확인해주는데요.학생들은보고서를쓰거나관련분야의전문가를만나인터뷰를하기도합니다.평가도학기가끝날때쯤스스로하는데결과에만족못했을땐다음학기에다시도전할수있습니다.
남자의중심생각으로맞는것을고르십시오.', NULL, 'https://ywtxdfwntobzegrlyplw.supabase.co/storage/v1/object/public/mock%20test%20files/topik-ii-37/audio/37th-TOPIK-II-Listening-Audio-File-64k-mono.mp3', NULL, '["자기계발은계획서작성이필요하다.", "진정한자기계발은스스로하는것이다.", "자기평가가안좋으면다시도전할수있다.", "자기계발의결과에대한만족도가중요하다."]'::jsonb, 2, '진정한자기계발은스스로하는것이다.', NULL),
  ((SELECT id FROM mock_test_bank WHERE exam_type = 'TOPIK_II' AND test_number = 37 ORDER BY created_at DESC LIMIT 1), 'listening', 26, '여자:선생님,이학교에는자기계발을스스로할수있는프로그램이있다고들었는데요.간단히소개해주시겠습니까?남자:네,자기계발프로그램은자기주도적으로이루어지는게중요한데우리학교의프로그램이그렇습니다.학생들은학기초에하고싶은일을정하고그중하나를골라계획서를제출합니다.학교에선중간에진도만확인해주는데요.학생들은보고서를쓰거나관련분야의전문가를만나인터뷰를하기도합니다.평가도학기가끝날때쯤스스로하는데결과에만족못했을땐다음학기에다시도전할수있습니다.
들은내용으로맞는것을고르십시오.', NULL, 'https://ywtxdfwntobzegrlyplw.supabase.co/storage/v1/object/public/mock%20test%20files/topik-ii-37/audio/37th-TOPIK-II-Listening-Audio-File-64k-mono.mp3', NULL, '["학생들은스스로계획서를작성한다.", "보고서를쓰려면전문가를만나야한다.", "학교가학생들의자기계발결과를평가한다.", "학생들은학기말에자기계발계획서를낸다."]'::jsonb, 2, '학생들은스스로계획서를작성한다.', NULL),
  ((SELECT id FROM mock_test_bank WHERE exam_type = 'TOPIK_II' AND test_number = 37 ORDER BY created_at DESC LIMIT 1), 'listening', 27, '여자:또선거운동이야?선거운동을하는건좋은데꼭저렇게시끄럽게해야돼?요즘에는조용한선거유세가늘고있다던데.남자:그러게.조용히악수를청하는후보자도있고손을흔들며인사하는후보자도있다는데말이야.여자:소리가크다고홍보가잘되는건아닌데.남자:그건모르지.후보들이각자자기를잘알릴수있는방법을선택하는거니까.뭐가좋고뭐가나쁘다고는말할수는없는것같아.여자:네말이맞긴한데,저런식의선거유세는오히려사람들한테반감만살걸.
여자가남자에게말하는의도를고르십시오.', NULL, 'https://ywtxdfwntobzegrlyplw.supabase.co/storage/v1/object/public/mock%20test%20files/topik-ii-37/audio/37th-TOPIK-II-Listening-Audio-File-64k-mono.mp3', NULL, '["후보자지지를부탁하기위해", "선거유세방법을비판하기위해", "선거유세효과를강조하기위해", "다양한홍보방법을확인하기위해"]'::jsonb, 2, '선거유세방법을비판하기위해', NULL),
  ((SELECT id FROM mock_test_bank WHERE exam_type = 'TOPIK_II' AND test_number = 37 ORDER BY created_at DESC LIMIT 1), 'listening', 28, '여자:또선거운동이야?선거운동을하는건좋은데꼭저렇게시끄럽게해야돼?요즘에는조용한선거유세가늘고있다던데.남자:그러게.조용히악수를청하는후보자도있고손을흔들며인사하는후보자도있다는데말이야.여자:소리가크다고홍보가잘되는건아닌데.남자:그건모르지.후보들이각자자기를잘알릴수있는방법을선택하는거니까.뭐가좋고뭐가나쁘다고는말할수는없는것같아.여자:네말이맞긴한데,저런식의선거유세는오히려사람들한테반감만살걸.
들은내용으로맞는것을고르십시오.', NULL, 'https://ywtxdfwntobzegrlyplw.supabase.co/storage/v1/object/public/mock%20test%20files/topik-ii-37/audio/37th-TOPIK-II-Listening-Audio-File-64k-mono.mp3', NULL, '["선거를할때유세방법을살펴야한다.", "큰소리로선거운동하는것은효과가좋다.", "사람들에게악수를건네는선거운동은불쾌감을준다.", "후보자는자신이원하는선거유세방법을선택한다."]'::jsonb, 2, '선거를할때유세방법을살펴야한다.', NULL),
  ((SELECT id FROM mock_test_bank WHERE exam_type = 'TOPIK_II' AND test_number = 37 ORDER BY created_at DESC LIMIT 1), 'listening', 29, '여자:문화재도손상되면수리가필요할텐데요.어떤부분에초점을두고수리해야할까요?남자:문화재를수리한다고하면보통뭔가새로운것으로교체해야한다고생각합니다.그런데문화재수리는손상된부분을단순히교체하는것이아니라원형을훼손시키지않는범위에서재창조하는것을의미합니다.이때중요한것은문화재에담긴고유한표현의도를벗어나서는안된다는것이죠.그래서저는그러한의도가제대로드러날때까지반복작업을수없이되풀이하곤합니다.그런데무엇보다중요한건귀중한문화재가손상되지않게잘관리하고보존하는것입니다.
남자는누구인지고르십시오.', NULL, 'https://ywtxdfwntobzegrlyplw.supabase.co/storage/v1/object/public/mock%20test%20files/topik-ii-37/audio/37th-TOPIK-II-Listening-Audio-File-64k-mono.mp3', NULL, '["문화재를복원하는사람", "문화재를관리하는사람", "문화재를해설하는사람", "문화재를발굴하는사람"]'::jsonb, 2, '문화재를해설하는사람', NULL),
  ((SELECT id FROM mock_test_bank WHERE exam_type = 'TOPIK_II' AND test_number = 37 ORDER BY created_at DESC LIMIT 1), 'listening', 30, '여자:문화재도손상되면수리가필요할텐데요.어떤부분에초점을두고수리해야할까요?남자:문화재를수리한다고하면보통뭔가새로운것으로교체해야한다고생각합니다.그런데문화재수리는손상된부분을단순히교체하는것이아니라원형을훼손시키지않는범위에서재창조하는것을의미합니다.이때중요한것은문화재에담긴고유한표현의도를벗어나서는안된다는것이죠.그래서저는그러한의도가제대로드러날때까지반복작업을수없이되풀이하곤합니다.그런데무엇보다중요한건귀중한문화재가손상되지않게잘관리하고보존하는것입니다.
들은내용으로맞는것을고르십시오.', NULL, 'https://ywtxdfwntobzegrlyplw.supabase.co/storage/v1/object/public/mock%20test%20files/topik-ii-37/audio/37th-TOPIK-II-Listening-Audio-File-64k-mono.mp3', NULL, '["문화재수리는작가에게책임이있다.", "문화재수리는반복되는교체작업이다.", "문화재수리는원형을훼손하지않아야한다.", "문화재수리는손상되지않게관리하는것이다."]'::jsonb, 2, '문화재수리는원형을훼손하지않아야한다.', NULL),
  ((SELECT id FROM mock_test_bank WHERE exam_type = 'TOPIK_II' AND test_number = 37 ORDER BY created_at DESC LIMIT 1), 'listening', 31, '여자:실업문제에대한여러가지대안들을말씀해주셨는데요.시간제일자리를늘리는게지금으로서는최선이라고생각합니다.남자:(부드러운반박톤으로)네,물론시간제일자리를늘리는게당장은효과가있겠지만근본적인문제를해결하기는어렵다고봅니다.오히려더큰문제를가져올수도있고요.여자:어떤문제가생길수있는지구체적으로말씀해주시겠습니까?남자:시간제일자리를늘리면그만큼신규채용의폭은줄어들수밖에없습니다.그렇게되면정규직을원하는사람들에겐오히려취업문이좁아져실업문제가더심각해질수도있습니다.
남자의생각으로맞는것을고르십시오.', NULL, 'https://ywtxdfwntobzegrlyplw.supabase.co/storage/v1/object/public/mock%20test%20files/topik-ii-37/audio/37th-TOPIK-II-Listening-Audio-File-64k-mono.mp3', NULL, '["정규직을늘리면실업문제를해결하기어렵다.", "신규채용의폭을줄여실업문제를해결할수있다.", "시간제일자리는실업문제를해결하는최선의방안이다.", "시간제일자리의확대는정규직취업기회를감소시킬수있다."]'::jsonb, 2, '시간제일자리의확대는정규직취업기회를감소시킬수있다.', NULL),
  ((SELECT id FROM mock_test_bank WHERE exam_type = 'TOPIK_II' AND test_number = 37 ORDER BY created_at DESC LIMIT 1), 'listening', 32, '여자:실업문제에대한여러가지대안들을말씀해주셨는데요.시간제일자리를늘리는게지금으로서는최선이라고생각합니다.남자:(부드러운반박톤으로)네,물론시간제일자리를늘리는게당장은효과가있겠지만근본적인문제를해결하기는어렵다고봅니다.오히려더큰문제를가져올수도있고요.여자:어떤문제가생길수있는지구체적으로말씀해주시겠습니까?남자:시간제일자리를늘리면그만큼신규채용의폭은줄어들수밖에없습니다.그렇게되면정규직을원하는사람들에겐오히려취업문이좁아져실업문제가더심각해질수도있습니다.
남자의태도로맞는것을고르십시오.', NULL, 'https://ywtxdfwntobzegrlyplw.supabase.co/storage/v1/object/public/mock%20test%20files/topik-ii-37/audio/37th-TOPIK-II-Listening-Audio-File-64k-mono.mp3', NULL, '["구체적인사례를들어주제를설명하고있다.", "객관적인자료를통해자신의의견을주장하고있다.", "근거를들어상대방의주장을부드럽게반박하고있다.", "상황을객관적으로분석하며상대방의견을지지하고있다."]'::jsonb, 2, '근거를들어상대방의주장을부드럽게반박하고있다.', NULL),
  ((SELECT id FROM mock_test_bank WHERE exam_type = 'TOPIK_II' AND test_number = 37 ORDER BY created_at DESC LIMIT 1), 'listening', 33, '남자:여러분,물이끓는과정을한번생각해볼까요?물은끓기전까지는변화가없죠.99도까지는에너지를품고있다가99도에서100도가되는순간에에너지를내며끓기시작합니다.바로그순간이없다면변화는기대하기힘들게되는거죠.우리의인생도마찬가지아닐까요?저와여러분의인생은성공과실패의가능성을모두가지고있습니다.하지만변화가일어날수있는마지막그순간에결정적인힘을발휘하는사람은성공을,그렇지못한사람은실패를맛보게되는거죠.여러분,1%의힘을발휘하는연습을해보십시오.성공은여러분의것입니다.
무엇에대한내용인지맞는것을고르십시오.', NULL, 'https://ywtxdfwntobzegrlyplw.supabase.co/storage/v1/object/public/mock%20test%20files/topik-ii-37/audio/37th-TOPIK-II-Listening-Audio-File-64k-mono.mp3', NULL, '["성공과실패가결정되는시기", "인생을배우며성장하는과정", "결과보다과정이중요한이유", "실패가가져오는긍정적변화"]'::jsonb, 2, '성공과실패가결정되는시기', NULL),
  ((SELECT id FROM mock_test_bank WHERE exam_type = 'TOPIK_II' AND test_number = 37 ORDER BY created_at DESC LIMIT 1), 'listening', 34, '남자:여러분,물이끓는과정을한번생각해볼까요?물은끓기전까지는변화가없죠.99도까지는에너지를품고있다가99도에서100도가되는순간에에너지를내며끓기시작합니다.바로그순간이없다면변화는기대하기힘들게되는거죠.우리의인생도마찬가지아닐까요?저와여러분의인생은성공과실패의가능성을모두가지고있습니다.하지만변화가일어날수있는마지막그순간에결정적인힘을발휘하는사람은성공을,그렇지못한사람은실패를맛보게되는거죠.여러분,1%의힘을발휘하는연습을해보십시오.성공은여러분의것입니다.
